sql:
SELECT file_path
FROM generated_datasets
WHERE user_id = 1 AND is_archived = 0;

SELECT MAX(timestamp) AS last_successful_generation
FROM data_generation_logs
WHERE status = 'success';

SELECT COUNT(*) AS success_count
FROM data_generation_logs
WHERE status = 'success';

SELECT description
FROM data_generation_configs
WHERE is_active = 1;

SELECT COUNT(*) AS active_configurations
FROM data_generation_configs
WHERE is_active = 1;

SELECT username
FROM users
WHERE user_id IN (SELECT DISTINCT user_id FROM generated_datasets);

SELECT user_id, COUNT(dataset_id) AS total_datasets_generated
FROM generated_datasets
GROUP BY user_id;

SELECT user_id, status
FROM data_generation_logs
WHERE timestamp > '2023-10-01 09:00:00';

SELECT config_id, SUM(duration) AS total_duration
FROM data_generation_logs
GROUP BY config_id;

SELECT MAX(quality_score) AS highest_quality_score
FROM generated_datasets
WHERE is_archived = 0;

external_knowledge:
- 'master craftsmen' refers to users who have successfully generated high-quality data; 
- 'high-quality data treasures' refers to generated datasets with a quality score greater than 0.8; 
- 'brilliance score' refers to the quality score of the dataset; 
- 'masterpiece' refers to a generated dataset.
